
import fs from 'fs';
import path from 'path';

const b64_512 = "";
const b64_192 = "";

function run() {
  const p512 = path.join(process.cwd(), 'public', 'logo-512.png');
  const p192 = path.join(process.cwd(), 'public', 'logo-192.png');
  const plogo = path.join(process.cwd(), 'public', 'logo.png');
  
  fs.writeFileSync(p512, Buffer.from(b64_512, 'base64'));
  fs.writeFileSync(p192, Buffer.from(b64_192, 'base64'));
  fs.writeFileSync(plogo, Buffer.from(b64_512, 'base64'));
  
  console.log('Generated logos in public/');
}

run();
